final:
module RefModule (
    input clk,
    input rst,
    input [3:0] state_input,
    output reg [3:0] control_output
);
    reg [3:0] pipeline_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            pipeline_reg <= 4'b0000;
        end else begin
            case (pipeline_reg)
                4'b0000: pipeline_reg <= (state_input[0]) ? 4'b0001 : 4'b0000;
                4'b0001: pipeline_reg <= (state_input[0]) ? 4'b0010 : 4'b0000;
                4'b0010: pipeline_reg <= (state_input[0]) ? 4'b0011 : 4'b0001;
                4'b0011: pipeline_reg <= (state_input[0]) ? 4'b0000 : 4'b0010;
                default: pipeline_reg <= 4'b0000;
            endcase
        end
    end

    always @(*) begin
        control_output = pipeline_reg;
    end
endmodule
